41	// Runs is the resolver for the runs field.
42	func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
43		provider, ok := r.State.(RunsStateProvider)
44		if !ok {
45			return emptyRunConnection(), nil
46		}
47		pid := ""
48		if projectID != nil {
49			pid = *projectID
50		}
51		filter := RunFilter{Layer: layer}
52		if beadID != nil {
53			filter.BeadID = *beadID
54		}
55		if status != nil {
56			filter.Status = *status
57		}
58		if harness != nil {
59			filter.Harness = *harness
60		}
61		all := provider.GetRunsGraphQL(pid, filter)
62		return runConnectionFrom(all, first, after), nil
63	}
