65	// Run is the resolver for the run field.
66	func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
67		provider, ok := r.State.(RunsStateProvider)
68		if !ok {
69			return nil, nil
70		}
71		wd := r.workingDir(ctx)
72		if wd == "" {
73			return nil, nil
74		}
75		projectID, ok := r.projectIDForWorkingDir(wd)
76		if !ok {
77			return nil, nil
78		}
79		run, ok := provider.GetRunGraphQL(id)
80		if !ok {
81			return nil, nil
82		}
83		if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) != projectID {
84			return nil, nil
85		}
86		r.recordRunDetailView(ctx, run)
87		if runHasRawTranscriptSelection(ctx) {
88			r.recordRawTranscriptViewed(ctx, run)
89		}
90		return run, nil
91	}
