105	// recordRunDetailView appends the canonical run_detail_view bead audit event
106	// the first time a project-scoped run detail is resolved for a specific run.
107	// Duplicate loads of the same run id are ignored, but distinct runs on the
108	// same bead remain auditable.
109	func (r *queryResolver) recordRunDetailView(ctx context.Context, run *Run) {
110		if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
111			return
112		}
113		if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
114			return
115		}
116		wd := r.workingDir(ctx)
117		if wd == "" {
118			return
119		}
120		if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
121			return
122		}
123	
124		store := bead.NewStore(filepath.Join(wd, ".ddx"))
125		if existing, err := store.EventsByKind(*run.BeadID, runDetailViewEventKind); err == nil {
126			for _, ev := range existing {
127				if strings.Contains(ev.Body, "run_id="+run.ID) {
128					return
129				}
130			}
131		}
132	
133		identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
134		if httpReq := httpRequestFromContext(ctx); httpReq != nil {
135			identity = operatorPromptIdentity(httpReq)
136		}
137		body := fmt.Sprintf(
138			"project_id=%s run_id=%s layer=%s visibility=project_membership",
139			*run.ProjectID,
140			run.ID,
141			run.Layer,
142		)
143		_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
144			Kind:    runDetailViewEventKind,
145			Summary: "run detail viewed",
146			Body:    body,
147			Actor:   identity.actor,
148			Source:  "graphql:run",
149		})
150	}
