152	func runHasRawTranscriptSelection(ctx context.Context) bool {
153		if !gqlgraphql.HasOperationContext(ctx) {
154			return false
155		}
156		for _, field := range gqlgraphql.CollectAllFields(ctx) {
157			switch field {
158			case "prompt", "response", "stderr":
159				return true
160			}
161		}
162		return false
163	}
164	
165	func rawTranscriptSelectionSummary(ctx context.Context) string {
166		if !gqlgraphql.HasOperationContext(ctx) {
167			return ""
168		}
169		selected := gqlgraphql.CollectAllFields(ctx)
170		ordered := make([]string, 0, 3)
171		for _, name := range []string{"prompt", "response", "stderr"} {
172			for _, field := range selected {
173				if field == name {
174					ordered = append(ordered, name)
175					break
176				}
177			}
178		}
179		return strings.Join(ordered, ",")
180	}
