261	func runToolCallConnectionFrom(calls []*RunToolCall, first *int, after *string) *RunToolCallConnection {
262		all := make([]*RunToolCallEdge, len(calls))
263		ids := make([]string, len(calls))
264		for i, c := range calls {
265			all[i] = &RunToolCallEdge{Node: c, Cursor: encodeStableCursor(c.ID)}
266			ids[i] = c.ID
267		}
268		startIdx, _ := stablePageBounds(ids, after, nil)
269		slice := all[startIdx:]
270		truncByFirst := false
271		if first != nil && *first >= 0 && *first < len(slice) {
272			slice = slice[:*first]
273			truncByFirst = true
274		}
275		pageInfo := &PageInfo{
276			HasPreviousPage: startIdx > 0,
277			HasNextPage:     truncByFirst,
278		}
279		if len(slice) > 0 {
280			pageInfo.StartCursor = &slice[0].Cursor
281			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
282		}
283		return &RunToolCallConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
284	}
