320	// applyRunFilter applies the filter to a list of runs.
321	func applyRunFilter(in []*Run, filter RunFilter) []*Run {
322		if len(in) == 0 {
323			return in
324		}
325		if filter.Layer == nil && filter.BeadID == "" && filter.Status == "" && filter.Harness == "" {
326			return in
327		}
328		out := in[:0:0]
329		for _, r := range in {
330			if filter.Layer != nil && r.Layer != *filter.Layer {
331				continue
332			}
333			if filter.BeadID != "" {
334				if r.BeadID == nil || *r.BeadID != filter.BeadID {
335					continue
336				}
337			}
338			if filter.Status != "" {
339				if !strings.EqualFold(r.Status, filter.Status) {
340					continue
341				}
342			}
343			if filter.Harness != "" {
344				if r.Harness == nil || *r.Harness != filter.Harness {
345					continue
346				}
347			}
348			out = append(out, r)
349		}
350		return out
351	}
