381	func TestAuditEvent_RawTranscriptViewed(t *testing.T) {
382		workDir, store := setupIntegrationDir(t)
383		base := newTestStateProvider(workDir, store)
384		projID := base.projects[0].ID
385		beadID := "ddx-raw-transcript"
386		if err := store.Create(&bead.Bead{ID: beadID, Title: "Raw transcript audit target", Status: bead.StatusOpen}); err != nil {
387			t.Fatalf("seed audit bead: %v", err)
388		}
389	
390		run := makeRun("run-raw-001", ddxgraphql.RunLayerRun, "success")
391		run.ProjectID = &projID
392		run.BeadID = &beadID
393		prompt := "prompt body"
394		response := "response body"
395		stderr := "stderr body"
396		run.Prompt = &prompt
397		run.Response = &response
398		run.Stderr = &stderr
399	
400		provider := &runsTestProvider{
401			testStateProvider: base,
402			all:               []*ddxgraphql.Run{run},
403		}
404		h := newGQLHandler(provider, workDir, nil)
405	
406		resp := gqlPost(t, h, `{ run(id: "run-raw-001") { id layer status artifactId } }`)
407		var headerOut struct {
408			Run *struct {
409				ID string `json:"id"`
410			} `json:"run"`
411		}
412		if err := json.Unmarshal(resp["data"], &headerOut); err != nil {
413			t.Fatalf("parse header query: %v", err)
414		}
415		if headerOut.Run == nil || headerOut.Run.ID != "run-raw-001" {
416			t.Fatalf("expected header query to resolve run, got %+v", headerOut.Run)
417		}
418		events, err := store.EventsByKind(beadID, "raw_transcript_viewed")
419		if err != nil {
420			t.Fatalf("get raw transcript events after header query: %v", err)
421		}
422		if len(events) != 0 {
423			t.Fatalf("expected no raw_transcript_viewed events before transcript access, got %d", len(events))
424		}
425	
426		resp = gqlPost(t, h, `{ run(id: "run-raw-001") { id prompt response stderr } }`)
427		var transcriptOut struct {
428			Run *struct {
429				ID       string  `json:"id"`
430				Prompt   *string `json:"prompt"`
431				Response *string `json:"response"`
432				Stderr   *string `json:"stderr"`
433			} `json:"run"`
434		}
435		if err := json.Unmarshal(resp["data"], &transcriptOut); err != nil {
436			t.Fatalf("parse transcript query: %v", err)
437		}
438		if transcriptOut.Run == nil || transcriptOut.Run.Prompt == nil || transcriptOut.Run.Response == nil || transcriptOut.Run.Stderr == nil {
439			t.Fatalf("expected transcript query to return prompt/response/stderr, got %+v", transcriptOut.Run)
440		}
441	
442		events, err = store.EventsByKind(beadID, "raw_transcript_viewed")
443		if err != nil {
444			t.Fatalf("get raw transcript events: %v", err)
445		}
446		if len(events) != 1 {
447			t.Fatalf("expected exactly 1 raw_transcript_viewed event, got %d", len(events))
448		}
449		if !strings.Contains(events[0].Body, "run_id=run-raw-001") {
450			t.Fatalf("raw transcript audit body missing run id: %q", events[0].Body)
451		}
452		if !strings.Contains(events[0].Body, "fields=prompt,response,stderr") {
453			t.Fatalf("raw transcript audit body missing transcript fields: %q", events[0].Body)
454		}
455		if !strings.Contains(events[0].Body, "visibility=project_membership") {
456			t.Fatalf("raw transcript audit body missing visibility marker: %q", events[0].Body)
457		}
