460	// TestRunFilter_LayerFilter covers applyRunFilter edge cases.
461	func TestRunFilter_LayerFilter(t *testing.T) {
462		work := ddxgraphql.RunLayerWork
463		try := ddxgraphql.RunLayerTry
464		run := ddxgraphql.RunLayerRun
465	
466		runs := []*ddxgraphql.Run{
467			makeRun("work-001", ddxgraphql.RunLayerWork, "success"),
468			makeRun("try-001", ddxgraphql.RunLayerTry, "success"),
469			makeRun("run-001", ddxgraphql.RunLayerRun, "success"),
470			makeRunWithHarness("run-002", ddxgraphql.RunLayerRun, "failure", "codex"),
471		}
472	
473		cases := []struct {
474			name    string
475			filter  ddxgraphql.RunFilter
476			wantLen int
477			wantIDs []string
478		}{
479			{"no filter", ddxgraphql.RunFilter{}, 4, nil},
480			{"layer=work", ddxgraphql.RunFilter{Layer: &work}, 1, []string{"work-001"}},
481			{"layer=try", ddxgraphql.RunFilter{Layer: &try}, 1, []string{"try-001"}},
482			{"layer=run", ddxgraphql.RunFilter{Layer: &run}, 2, nil},
483			{"status=failure", ddxgraphql.RunFilter{Status: "failure"}, 1, []string{"run-002"}},
484			{"status=success", ddxgraphql.RunFilter{Status: "success"}, 3, nil},
485			{"harness=claude", ddxgraphql.RunFilter{Harness: "claude"}, 1, []string{"run-001"}},
486		}
487	
488		for _, tc := range cases {
489			t.Run(tc.name, func(t *testing.T) {
490				got := ddxgraphql.ApplyRunFilter(runs, tc.filter)
491				if len(got) != tc.wantLen {
492					t.Fatalf("filter %q: expected %d runs, got %d", tc.name, tc.wantLen, len(got))
493				}
494				for _, wantID := range tc.wantIDs {
495					found := false
496					for _, r := range got {
497						if r.ID == wantID {
498							found = true
499							break
500						}
501					}
502					if !found {
503						t.Fatalf("filter %q: expected run %q in result", tc.name, wantID)
504					}
505				}
506			})
507		}
508	}
